example_bad:
trait Parser {
    fn parse<'a>(&self, input: &'a str) -> &'a str;
}

struct MyParser;

impl Parser for MyParser {
    fn parse(&self, input: &str) -> &str { // Error: lifetime mismatch
        input
    }
}

fixes.code:
impl Parser for MyParser {
    fn parse<'a>(&self, input: &'a str) -> &'a str {
        input
    }
}
